#include <iostream>
#include <vector>
#include <algorithm>

// Function to swap two elements
void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

bool bubble_sort(std::vector<int>& nums) {
    int n = nums.size();
    for (int i = 0; i < n-1; i++) {
        for (int j = 0; j < n-1; j++) {
            if (nums[j] > nums[j+1]) {
                // Correct swap
                swap(nums[j], nums[j+1]);
            }
        }
    }
    return true;
}

int main() {
    std::vector<int> nums = {5, 3, 8, 4, 2};
    bubble_sort(nums);
    for (int num : nums) {
        std::cout << num << ' '; 
    }
    return 0;
}

