import sys

def bubble_sort(self, nums: list[int]) -> None:
    n = len(nums)
    for i in range(n-1):
        for j in range(n-1):
            if nums[j] > nums[j+1]:
                # Correct swap
                nums[j], nums[j+1] = nums[j+1], nums[j]
    return None

